package dev.codedefense.application;import dev.codedefense.change.*;import dev.codedefense.cli.ExitCodes;import dev.codedefense.domain.*;import dev.codedefense.passport.*;import java.io.PrintWriter;import java.nio.file.Path;import java.util.Objects;
public final class MatchChangeHandoffUseCase {private final ChangeHandoffFileStore store;private final ChangeHandoffJsonCodec codec;private final GitChangeSource source;private final ChangeHandoffTerminalRenderer renderer;public MatchChangeHandoffUseCase(ChangeHandoffFileStore s,ChangeHandoffJsonCodec c,GitChangeSource source,ChangeHandoffTerminalRenderer r){store=Objects.requireNonNull(s);codec=Objects.requireNonNull(c);this.source=Objects.requireNonNull(source);renderer=Objects.requireNonNull(r);}public int match(Path input,Path repository,PrintWriter out,PrintWriter err){DecodedChangeHandoff decoded=codec.decode(store.read(input));if(decoded.integrity()!=HandoffIntegrity.INTACT){err.println("The Change Handoff is corrupt and cannot be matched.");return ExitCodes.INVALID_MODEL_RESPONSE;}var h=decoded.handoff();ChangeSelector selector=switch(h.changeKind()){case STAGED->new StagedSelector();case COMMIT->new CommitSelector(h.sourceIdentity());case RANGE->new RangeSelector(h.baseCommit(),h.sourceIdentity());};try{var identity=source.captureIdentity(repository,selector);HandoffMatchStatus status=identity.diffFingerprint().equals(h.diffFingerprint())?HandoffMatchStatus.MATCHES_LOCAL_CHANGE:HandoffMatchStatus.DIFFERENT_LOCAL_CHANGE;renderer.renderMatch(status,out);return status==HandoffMatchStatus.MATCHES_LOCAL_CHANGE?ExitCodes.SUCCESS:ExitCodes.GIT_EXECUTION_FAILED;}catch(GitChangeException e){renderer.renderMatch(HandoffMatchStatus.LOCAL_CHANGE_UNAVAILABLE,out);return ExitCodes.GIT_EXECUTION_FAILED;}}}
